import re
import spacy

nlp = spacy.load('en_core_web_trf')

PATTERNS = {
    'email': r'[\w.-]+@[\w.-]+\.\w{2,}',
    'ssn':   r'\b\d{3}-\d{2}-\d{4}\b',
    'phone': r'\b\+?1?[-.\s]?\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}\b',
}

def scrub_pii(text):
    # Regex pass for structured PII
    for label, pattern in PATTERNS.items():
        text = re.sub(pattern, f'[{label.upper()}]', text)
    # NER pass for named entities
    doc = nlp(text)
    for ent in reversed(doc.ents):
        if ent.label_ in ('PERSON', 'GPE', 'ORG', 'LOC'):
            text = text[:ent.start_char] + f'[{ent.label_}]' + text[ent.end_char:]
    return text
